package com.schwab.urlShortener.api;

import com.google.zxing.BarcodeFormat;
import com.google.zxing.WriterException;
import com.google.zxing.client.j2se.MatrixToImageWriter;
import com.google.zxing.common.BitMatrix;
import com.google.zxing.qrcode.QRCodeWriter;
import com.schwab.urlShortener.dto.CreateLinkRequest;
import com.schwab.urlShortener.dto.LinkStatsResponse;
import com.schwab.urlShortener.dto.ShortLinkResponse;
import com.schwab.urlShortener.service.ShortLinkService;
import jakarta.validation.Valid;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.ByteArrayOutputStream;
import java.io.IOException;

@RestController
@RequestMapping("/api/v1/links")
public class ShortLinkController {

    private final ShortLinkService service;
    private final String baseUrl;
    private final String redirectPath;

    public ShortLinkController(
            ShortLinkService service,
            @Value("${app.base-url}") String baseUrl,
            @Value("${app.redirect-path}") String redirectPath) {
        this.service = service;
        this.baseUrl = baseUrl;
        this.redirectPath = redirectPath;
    }

    @PostMapping
    public ResponseEntity<ShortLinkResponse> createShortLink(@Valid @RequestBody CreateLinkRequest request) {
        var link = service.createShortLink(request.targetUrl());
        var response = ShortLinkResponse.from(link, baseUrl, redirectPath);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @GetMapping("/{shortCode}")
    public ResponseEntity<ShortLinkResponse> getShortLink(@PathVariable String shortCode) {
        var link = service.resolve(shortCode);
        var response = ShortLinkResponse.from(link, baseUrl, redirectPath);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{shortCode}/stats")
    public ResponseEntity<LinkStatsResponse> getStats(@PathVariable String shortCode) {
        var link = service.resolve(shortCode);
        var stats = service.getStats(shortCode);
        return ResponseEntity.ok(LinkStatsResponse.from(link, stats, baseUrl, redirectPath));
    }

    @GetMapping("/{shortCode}/qr")
    public ResponseEntity<byte[]> getQrCode(@PathVariable String shortCode) throws WriterException, IOException {
        var link = service.resolve(shortCode);
        String shortUrl = baseUrl + redirectPath + "/" + link.getShortCode();

        QRCodeWriter qrCodeWriter = new QRCodeWriter();
        BitMatrix bitMatrix = qrCodeWriter.encode(shortUrl, BarcodeFormat.QR_CODE, 250, 250);

        ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
        MatrixToImageWriter.writeToStream(bitMatrix, "PNG", outputStream);
        byte[] qrCodeBytes = outputStream.toByteArray();

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.IMAGE_PNG);

        return ResponseEntity.ok()
                .headers(headers)
                .body(qrCodeBytes);
    }
}

package com.schwab.urlShortener.api;

import com.google.zxing.WriterException;
import com.schwab.urlShortener.exception.InvalidUrlException;
import com.schwab.urlShortener.exception.ShortLinkNotFoundException;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.io.IOException;
import java.net.URI;
import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ProblemDetail handleValidationExceptions(MethodArgumentNotValidException ex) {
        Map<String, String> errors = new HashMap<>();
        ex.getBindingResult().getAllErrors().forEach((error) -> {
            String fieldName = ((FieldError) error).getField();
            String errorMessage = error.getDefaultMessage();
            errors.put(fieldName, errorMessage);
        });

        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.BAD_REQUEST, "Validation failed");
        problemDetail.setType(URI.create("https://api.schwab.com/problems/validation-error"));
        problemDetail.setTitle("Validation Error");
        problemDetail.setProperty("errors", errors);
        return problemDetail;
    }

    @ExceptionHandler(ShortLinkNotFoundException.class)
    public ProblemDetail handleShortLinkNotFound(ShortLinkNotFoundException ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.NOT_FOUND, ex.getMessage());
        problemDetail.setType(URI.create("https://api.schwab.com/problems/not-found"));
        problemDetail.setTitle("Short Link Not Found");
        return problemDetail;
    }

    @ExceptionHandler(InvalidUrlException.class)
    public ProblemDetail handleInvalidUrl(InvalidUrlException ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(HttpStatus.BAD_REQUEST, ex.getMessage());
        problemDetail.setType(URI.create("https://api.schwab.com/problems/invalid-url"));
        problemDetail.setTitle("Invalid URL");
        return problemDetail;
    }

    @ExceptionHandler({WriterException.class, IOException.class})
    public ProblemDetail handleQrCodeGenerationFailure(Exception ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
                HttpStatus.INTERNAL_SERVER_ERROR, 
                "Failed to generate QR code");
        problemDetail.setType(URI.create("https://api.schwab.com/problems/qr-generation-error"));
        problemDetail.setTitle("QR Code Generation Error");
        return problemDetail;
    }

    @ExceptionHandler(Exception.class)
    public ProblemDetail handleGenericException(Exception ex) {
        ProblemDetail problemDetail = ProblemDetail.forStatusAndDetail(
                HttpStatus.INTERNAL_SERVER_ERROR,
                "An unexpected error occurred");
        problemDetail.setType(URI.create("https://api.schwab.com/problems/internal-error"));
        problemDetail.setTitle("Internal Server Error");
        return problemDetail;
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.dto.LinkStats;
import com.schwab.urlShortener.exception.ShortLinkNotFoundException;
import com.schwab.urlShortener.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.time.Instant;

import static org.hamcrest.Matchers.*;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(ShortLinkController.class)
class ShortLinkControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private ShortLinkService service;

    @Test
    void testCreateShortLink() throws Exception {
        var now = Instant.now();
        var link = new ShortLink("abc123", "https://example.com", now);
        when(service.createShortLink("https://example.com")).thenReturn(link);

        mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"targetUrl\":\"https://example.com\"}"))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.shortCode").value("abc123"))
                .andExpect(jsonPath("$.targetUrl").value("https://example.com"))
                .andExpect(jsonPath("$.shortUrl").exists());
    }

    @Test
    void testCreateShortLink_InvalidUrl() throws Exception {
        mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"targetUrl\":\"not-a-url\"}"))
                .andExpect(status().isBadRequest())
                .andExpect(jsonPath("$.title").value("Validation Error"));
    }

    @Test
    void testGetShortLink() throws Exception {
        var now = Instant.now();
        var link = new ShortLink("abc123", "https://example.com", now);
        when(service.resolve("abc123")).thenReturn(link);

        mockMvc.perform(get("/api/v1/links/abc123"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.shortCode").value("abc123"))
                .andExpect(jsonPath("$.targetUrl").value("https://example.com"));
    }

    @Test
    void testGetShortLink_NotFound() throws Exception {
        when(service.resolve("nonexistent")).thenThrow(new ShortLinkNotFoundException("nonexistent"));

        mockMvc.perform(get("/api/v1/links/nonexistent"))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.title").value("Short Link Not Found"));
    }

    @Test
    void testGetStats() throws Exception {
        var now = Instant.now();
        var link = new ShortLink("abc123", "https://example.com", now);
        var stats = new LinkStats(42L, now);
        when(service.resolve("abc123")).thenReturn(link);
        when(service.getStats("abc123")).thenReturn(stats);

        mockMvc.perform(get("/api/v1/links/abc123/stats"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.shortCode").value("abc123"))
                .andExpect(jsonPath("$.accessCount").value(42));
    }

    @Test
    void testGetQrCode_Success() throws Exception {
        var now = Instant.now();
        var link = new ShortLink("abc123", "https://example.com", now);
        when(service.resolve("abc123")).thenReturn(link);

        mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andExpect(content().bytes(notNullValue()))
                .andExpect(header().string("Content-Type", "image/png"));
    }

    @Test
    void testGetQrCode_NotFound() throws Exception {
        when(service.resolve("nonexistent")).thenThrow(new ShortLinkNotFoundException("nonexistent"));

        mockMvc.perform(get("/api/v1/links/nonexistent/qr"))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.title").value("Short Link Not Found"));
    }
}

package com.schwab.urlShortener;

import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.repository.ShortLinkRepository;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.cache.CacheManager;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import static org.hamcrest.Matchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
class ShortLinkIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ShortLinkRepository repository;

    @Autowired
    private CacheManager cacheManager;

    @BeforeEach
    void setUp() {
        repository.deleteAll();
        cacheManager.getCacheNames().forEach(cacheName ->
                cacheManager.getCache(cacheName).clear());
    }

    @Test
    void testCreateAndRetrieveShortLink() throws Exception {
        String createResponse = mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"targetUrl\":\"https://example.com\"}"))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.shortCode").exists())
                .andExpect(jsonPath("$.targetUrl").value("https://example.com"))
                .andReturn()
                .getResponse()
                .getContentAsString();

        String shortCode = createResponse.split("\"shortCode\":\"")[1].split("\"")[0];

        mockMvc.perform(get("/api/v1/links/" + shortCode))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.shortCode").value(shortCode))
                .andExpect(jsonPath("$.targetUrl").value("https://example.com"));
    }

    @Test
    void testRedirectIncrementsAccessCount() throws Exception {
        String createResponse = mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"targetUrl\":\"https://example.com\"}"))
                .andExpect(status().isCreated())
                .andReturn()
                .getResponse()
                .getContentAsString();

        String shortCode = createResponse.split("\"shortCode\":\"")[1].split("\"")[0];

        mockMvc.perform(get("/s/" + shortCode))
                .andExpect(status().isFound())
                .andExpect(header().string("Location", "https://example.com"));

        mockMvc.perform(get("/api/v1/links/" + shortCode + "/stats"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.accessCount").value(1));
    }

    @Test
    void testGetNonExistentShortLink() throws Exception {
        mockMvc.perform(get("/api/v1/links/nonexistent"))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.title").value("Short Link Not Found"));
    }

    @Test
    void testRedirectNonExistentShortCode() throws Exception {
        mockMvc.perform(get("/s/nonexistent"))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.title").value("Short Link Not Found"));
    }

    @Test
    void testInvalidUrlValidation() throws Exception {
        mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"targetUrl\":\"not-a-valid-url\"}"))
                .andExpect(status().isBadRequest())
                .andExpect(jsonPath("$.title").value("Validation Error"));
    }

    @Test
    void testQrCodeEndpoint() throws Exception {
        String createResponse = mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"targetUrl\":\"https://example.com\"}"))
                .andExpect(status().isCreated())
                .andReturn()
                .getResponse()
                .getContentAsString();

        String shortCode = createResponse.split("\"shortCode\":\"")[1].split("\"")[0];

        byte[] qrCodeBytes = mockMvc.perform(get("/api/v1/links/" + shortCode + "/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andExpect(header().string("Content-Type", "image/png"))
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        assert qrCodeBytes.length > 0;
        assert qrCodeBytes[0] == (byte) 0x89;
        assert qrCodeBytes[1] == (byte) 0x50;
        assert qrCodeBytes[2] == (byte) 0x4E;
        assert qrCodeBytes[3] == (byte) 0x47;
    }

    @Test
    void testQrCodeEndpoint_NotFound() throws Exception {
        mockMvc.perform(get("/api/v1/links/nonexistent/qr"))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.title").value("Short Link Not Found"));
    }
}

package com.schwab.urlShortener.api;

import com.google.zxing.BarcodeFormat;
import com.google.zxing.BinaryBitmap;
import com.google.zxing.MultiFormatReader;
import com.google.zxing.Result;
import com.google.zxing.client.j2se.BufferedImageLuminanceSource;
import com.google.zxing.common.HybridBinarizer;
import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.exception.ShortLinkNotFoundException;
import com.schwab.urlShortener.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.context.TestPropertySource;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;

import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.time.Instant;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(ShortLinkController.class)
@TestPropertySource(properties = {
        "app.base-url=https://short.test",
        "app.redirect-path=/s"
})
class ShortLinkControllerQrCodeTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private ShortLinkService service;

    @Test
    void qrCodeContainsCorrectShortUrl() throws Exception {
        var link = new ShortLink("xyz789", "https://example.com/target", Instant.now());
        when(service.resolve("xyz789")).thenReturn(link);

        MvcResult result = mockMvc.perform(get("/api/v1/links/xyz789/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andReturn();

        byte[] qrCodeBytes = result.getResponse().getContentAsByteArray();
        String decodedUrl = decodeQrCode(qrCodeBytes);

        assertThat(decodedUrl).isEqualTo("https://short.test/s/xyz789");
    }

    @Test
    void qrCodeReturnsValidPngImage() throws Exception {
        var link = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(link);

        MvcResult result = mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andReturn();

        byte[] qrCodeBytes = result.getResponse().getContentAsByteArray();

        // Verify PNG header (magic bytes)
        assertThat(qrCodeBytes).hasSizeGreaterThan(8);
        assertThat(qrCodeBytes[0]).isEqualTo((byte) 0x89);
        assertThat(qrCodeBytes[1]).isEqualTo((byte) 0x50);
        assertThat(qrCodeBytes[2]).isEqualTo((byte) 0x4E);
        assertThat(qrCodeBytes[3]).isEqualTo((byte) 0x47);

        // Verify it can be read as an image
        BufferedImage image = ImageIO.read(new ByteArrayInputStream(qrCodeBytes));
        assertThat(image).isNotNull();
        assertThat(image.getWidth()).isEqualTo(250);
        assertThat(image.getHeight()).isEqualTo(250);
    }

    @Test
    void qrCodeEndpointReturnsNotFoundWhenShortCodeDoesNotExist() throws Exception {
        when(service.resolve("missing")).thenThrow(new ShortLinkNotFoundException("missing"));

        mockMvc.perform(get("/api/v1/links/missing/qr"))
                .andExpect(status().isNotFound())
                .andExpect(jsonPath("$.title").value("Short Link Not Found"))
                .andExpect(jsonPath("$.detail").value("Short link not found: missing"));
    }

    @Test
    void qrCodeHandlesShortCodesWithSpecialCharacters() throws Exception {
        var link = new ShortLink("a-b_c1", "https://example.com", Instant.now());
        when(service.resolve("a-b_c1")).thenReturn(link);

        MvcResult result = mockMvc.perform(get("/api/v1/links/a-b_c1/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andReturn();

        byte[] qrCodeBytes = result.getResponse().getContentAsByteArray();
        String decodedUrl = decodeQrCode(qrCodeBytes);

        assertThat(decodedUrl).isEqualTo("https://short.test/s/a-b_c1");
    }

    @Test
    void qrCodeHandlesLongTargetUrls() throws Exception {
        String longUrl = "https://example.com/very/long/path/with/many/segments/and/query?param1=value1&param2=value2&param3=value3";
        var link = new ShortLink("short1", longUrl, Instant.now());
        when(service.resolve("short1")).thenReturn(link);

        MvcResult result = mockMvc.perform(get("/api/v1/links/short1/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andReturn();

        byte[] qrCodeBytes = result.getResponse().getContentAsByteArray();
        String decodedUrl = decodeQrCode(qrCodeBytes);

        // QR code should contain the SHORT URL, not the target URL
        assertThat(decodedUrl).isEqualTo("https://short.test/s/short1");
        assertThat(decodedUrl).doesNotContain(longUrl);
    }

    @Test
    void qrCodeSetsCorrectHttpHeaders() throws Exception {
        var link = new ShortLink("test123", "https://example.com", Instant.now());
        when(service.resolve("test123")).thenReturn(link);

        mockMvc.perform(get("/api/v1/links/test123/qr"))
                .andExpect(status().isOk())
                .andExpect(header().string("Content-Type", "image/png"))
                .andExpect(content().contentType(MediaType.IMAGE_PNG));
    }

    @Test
    void qrCodeReturnsNonEmptyByteArray() throws Exception {
        var link = new ShortLink("abc", "https://example.com", Instant.now());
        when(service.resolve("abc")).thenReturn(link);

        MvcResult result = mockMvc.perform(get("/api/v1/links/abc/qr"))
                .andExpect(status().isOk())
                .andReturn();

        byte[] qrCodeBytes = result.getResponse().getContentAsByteArray();
        assertThat(qrCodeBytes).isNotEmpty();
        assertThat(qrCodeBytes.length).isGreaterThan(100); // QR codes should be reasonably sized
    }

    private String decodeQrCode(byte[] qrCodeBytes) throws Exception {
        BufferedImage image = ImageIO.read(new ByteArrayInputStream(qrCodeBytes));
        BinaryBitmap binaryBitmap = new BinaryBitmap(
                new HybridBinarizer(new BufferedImageLuminanceSource(image)));
        Result result = new MultiFormatReader().decode(binaryBitmap);
        assertThat(result.getBarcodeFormat()).isEqualTo(BarcodeFormat.QR_CODE);
        return result.getText();
    }
}

package com.schwab.urlShortener.api;

import com.google.zxing.WriterException;
import org.junit.jupiter.api.Test;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;

import java.io.IOException;

import static org.assertj.core.api.Assertions.assertThat;

class GlobalExceptionHandlerQrCodeTest {

    private final GlobalExceptionHandler handler = new GlobalExceptionHandler();

    @Test
    void writerExceptionReturnsInternalServerError() {
        WriterException exception = new WriterException("QR encoding failed");

        ProblemDetail problemDetail = handler.handleQrCodeGenerationFailure(exception);

        assertThat(problemDetail.getStatus()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR.value());
        assertThat(problemDetail.getTitle()).isEqualTo("QR Code Generation Error");
        assertThat(problemDetail.getDetail()).isEqualTo("Failed to generate QR code");
        assertThat(problemDetail.getType().toString()).isEqualTo("https://api.schwab.com/problems/qr-generation-error");
    }

    @Test
    void ioExceptionReturnsInternalServerError() {
        IOException exception = new IOException("Failed to write PNG");

        ProblemDetail problemDetail = handler.handleQrCodeGenerationFailure(exception);

        assertThat(problemDetail.getStatus()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR.value());
        assertThat(problemDetail.getTitle()).isEqualTo("QR Code Generation Error");
        assertThat(problemDetail.getDetail()).isEqualTo("Failed to generate QR code");
        assertThat(problemDetail.getType().toString()).isEqualTo("https://api.schwab.com/problems/qr-generation-error");
    }

    @Test
    void qrCodeGenerationErrorDoesNotExposeInternalDetails() {
        WriterException exception = new WriterException("Internal: database connection failed");

        ProblemDetail problemDetail = handler.handleQrCodeGenerationFailure(exception);

        // Should return generic error message, not the internal exception message
        assertThat(problemDetail.getDetail()).isEqualTo("Failed to generate QR code");
        assertThat(problemDetail.getDetail()).doesNotContain("database");
        assertThat(problemDetail.getDetail()).doesNotContain("Internal");
    }

    @Test
    void qrCodeErrorHandlerAcceptsBothExceptionTypes() {
        // Verify the handler can handle both WriterException and IOException
        WriterException writerException = new WriterException();
        IOException ioException = new IOException();

        ProblemDetail writerResult = handler.handleQrCodeGenerationFailure(writerException);
        ProblemDetail ioResult = handler.handleQrCodeGenerationFailure(ioException);

        assertThat(writerResult.getStatus()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR.value());
        assertThat(ioResult.getStatus()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR.value());
        assertThat(writerResult.getTitle()).isEqualTo(ioResult.getTitle());
        assertThat(writerResult.getDetail()).isEqualTo(ioResult.getDetail());
    }
}
